import React, { useState } from 'react';
import axios from "axios";
import { useNavigate } from 'react-router-dom';  // Import useNavigate

axios.defaults.withCredentials = true; // Ensure cookies are included in requests

// import {config} from "dotenv";

const LoginPage = () => {
    // const [email, setEmail] = useState('');
    const [userName, setUserName] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const [isLoading, setIsLoading] = useState(false);

    const navigate = useNavigate();  // Initialize the navigate hook

    const handleSubmit = async (e) => {
        console.log("handleSubmit", e);
        e.preventDefault();

        console.log("Login with:\nemail: " + userName + "\nPassword: " + password);

        if (!userName || !password) {
            setError('Please enter both userName and password');
            return;
        }

        setIsLoading(true);
        setError('');

        console.log("HERERE");
        try {
            let response= await axios.post("http://localhost:3003/user/login", {
                username: userName,
                password: password
            })

            console.log("response is: " + response);

            if (200 !== response.status) {
                console.log("response.status: " + response.status);
                console.log("response.data: " + response.data);
                throw new Error('Login failed, please try again.');
            }

            // Handle successful login here (e.g., redirect to dashboard)
            console.log('Login successful');

            let data = response.data;
            navigate('/profile', { state: { data } });

            // Redirect to profile page
        } catch (err) {
            setError(err.message || 'An error occurred');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div style={styles.container}>
            <h2>Login to Your Account</h2>
            {error && <div style={styles.error}>{error}</div>}
            <form onSubmit={handleSubmit}>
                <div style={styles.inputContainer}>
                    <label>User Name</label>
                    <input
                        type="string"
                        value={userName}
                        onChange={(e) => setUserName(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your user name"
                    />
                </div>
                <div style={styles.inputContainer}>
                    <label>Password</label>
                    <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        style={styles.input}
                        placeholder="Enter your password"
                    />
                </div>
                <button type="submit" style={styles.button} disabled={isLoading}>
                    {isLoading ? 'Logging in...' : 'Login'}
                </button>
            </form>
            <div style={styles.redirect}>
                <p>Don't have an account? <a href="/register">Register here</a></p>
            </div>
        </div>
    );
};

const styles = {
    container: {
        maxWidth: '400px',
        margin: 'auto',
        padding: '20px',
        backgroundColor: '#f9f9f9',
        borderRadius: '8px',
        boxShadow: '0 4px 8px rgba(0, 0, 0, 0.1)',
    },
    inputContainer: {
        marginBottom: '15px',
    },
    input: {
        width: '100%',
        padding: '10px',
        marginTop: '5px',
        borderRadius: '5px',
        border: '1px solid #ccc',
    },
    button: {
        width: '100%',
        padding: '12px',
        backgroundColor: '#007bff',
        color: 'white',
        border: 'none',
        borderRadius: '5px',
        fontSize: '16px',
        cursor: 'pointer',
    },
    error: {
        color: 'red',
        marginBottom: '10px',
    },
    redirect: {
        marginTop: '10px',
        textAlign: 'center',
    },
};

export default LoginPage;
